init_eqs:
red_rez = rand(1);
green_rez = rand(1);
blue_rez = rand(1);
beatsize = rand(1);
beatsize2 = rand(1)/7.5;
ifnegbeat = int(rand(2));
swirlsize = rand(1);
opsize = min(.25, rand(1));

timesync = 0;

frame_eqs:
warp=0;
wave_r = wave_r + 0.45*(0.5*sin(time*0.701)+ 0.3*cos(time*0.438));
wave_b = wave_b - 0.4*(0.5*sin(time*4.782)+0.5*cos(time*0.522));
wave_g = wave_g + 0.4*sin(time*1.731);

timesync += 1/fps;
if(timesync >= .5 && bass >= 1.8, beat = 1; timesync = 0, beat = 0);

ifnegbeat = if(beat, int(rand(2)), ifnegbeat);
red_rez = if(beat, rand(1), red_rez);
green_rez = if(beat, rand(1), green_rez);
blue_rez = if(beat, rand(1), blue_rez);
beatsize = if(beat, rand(1), beatsize);
beatsize2 = if(beat, rand(1)/7.5, beatsize2);
swirlsize = if(beat, rand(1), swirlsize);
opsize = if(beat, min(.25, rand(1)), opsize);

swirldir = if(ifnegbeat, 1, -1);
q3 = swirldir;
q4 = swirlsize;

ib_r = red_rez;
ib_g = green_rez;
ib_b = blue_rez;
ob_size = beatsize;
ib_size = beatsize2;
ib_a = opsize;

decay = decay - equal(beat,1)*0.1;
vol = 0.167*(bass+mid);
xamptarg = if(equal(frame%15,0),min(0.5*vol*bass_att,0.5),xamptarg);
xamp = xamp + 0.5*(xamptarg-xamp);
xdir = if(above(abs(xpos),xamp),-sign(xpos),if(below(abs(xspeed),0.1),2*above(xpos,0)-1,xdir));
xspeed = xspeed + xdir*xamp - xpos - xspeed*0.055*below(abs(xpos),xamp);
xpos = xpos + 0.001*xspeed;
wave_x = 1.5*xpos + 0.5;
yamptarg = if(equal(frame%15,0),min(0.3*vol*treb_att,0.5),yamptarg);
yamp = yamp + 0.5*(yamptarg-yamp);
ydir = if(above(abs(ypos),yamp),-sign(ypos),if(below(abs(yspeed),0.1),2*above(ypos,0)-1,ydir));
yspeed = yspeed + ydir*yamp - ypos - yspeed*0.055*below(abs(ypos),yamp);
ypos = ypos + 0.001*yspeed;
wave_y = 1.5*ypos + 0.5;
q1 = xpos;
q2 = -ypos;

pixel_eqs:
ux = x*2 - 1  - q1*3;
uy = y*2 - 1  - q2*3;
dist = sqrt(sqr(ux) + sqr(uy));
mult = (q4*(sin(time/5))*.025) / dist;
swirl = atan2(q3*ux, q3*uy);
dx = sin(swirl-1.5)*mult;
dy = cos(swirl-1.5)*mult;
